import{_ as a,o as n,c as s,e}from"./app-2dc9ef31.js";const o={},p=e(`<p>在前端性能优化中,<code>首屏优化</code>非常重要!</p><h3 id="_1、路由懒加载" tabindex="-1"><a class="header-anchor" href="#_1、路由懒加载" aria-hidden="true">#</a> 1、路由懒加载</h3><p>SPA 项目，一个路由对应一个页面，如果不做处理，项目打包后，会把所有页面打包成一个文件，当用户打开首页时，会一次性加载所有的资源，造成首页加载很慢，降低用户体验。 将路由全都改为懒加载时，会发现，重新打包后，首页资源拆分为 <code>app.js</code> 和 <code>home.js</code>，以及对应的 <code>css</code> 文件 =&gt; 首页资源大大压缩</p><h4 id="路由懒加载的原理" tabindex="-1"><a class="header-anchor" href="#路由懒加载的原理" aria-hidden="true">#</a> 路由懒加载的原理</h4><p>懒加载前提的实现：ES6的动态地加载模块——<code>import()</code></p><blockquote><p>调用 import() 之处，被作为分离的模块起点，意思是，被请求的模块和它引用的所有子模块，会分离到一个单独的 chunk 中 要实现懒加载，就得先将进行懒加载的子模块分离出来，打包成一个单独的文件</p></blockquote><p>webpackChunkName 作用是 webpack 在打包的时候，对异步引入的库代码（lodash）进行代码分割时，设置代码块的名字。 webpack 会将任何一个异步模块与相同的块名称组合到相同的异步块中</p><h3 id="_2、组件懒加载" tabindex="-1"><a class="header-anchor" href="#_2、组件懒加载" aria-hidden="true">#</a> 2、组件懒加载</h3><p>除了路由的懒加载外，组件的懒加载在很多场景下也有重要的作用 举个简单的例子: home 页面 和 about 页面，都引入了 dialogInfo 弹框组件，该弹框不是一进入页面就加载，而是需要用户手动触发后才展示出来 项目打包后，发现 home.js 和 about.js 均包括了该弹框组件的代码（在 dist 文件中搜索dialogInfo弹框组件） 当用户打开 home 页时，会一次性加载该页面所有的资源，我们期望的是用户触发按钮后，再加载该弹框组件的资源 这种场景下，就很适合用懒加载的方式引入 弹框组件懒加载：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token operator">&lt;</span>script<span class="token operator">&gt;</span>
<span class="token keyword">const</span> <span class="token function-variable function">dialog</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token keyword">import</span><span class="token punctuation">(</span><span class="token comment">/* webpackChunkName: &quot;dialogInfo&quot; */</span> <span class="token string">&#39;@/components/dialogInfo&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&#39;homeView&#39;</span><span class="token punctuation">,</span>
  <span class="token literal-property property">components</span><span class="token operator">:</span> <span class="token punctuation">{</span>
    dialogInfo
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
<span class="token operator">&lt;</span><span class="token operator">/</span>script<span class="token operator">&gt;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>重新打包后，home.js 和 about.js 中没有了弹框组件的代码，该组件被独立打包成 dialogInfo.js，当用户点击按钮时，才会去加载 dialogInfo.js 和 dialogInfo.css</p><h4 id="组件懒加载的使用场景" tabindex="-1"><a class="header-anchor" href="#组件懒加载的使用场景" aria-hidden="true">#</a> 组件懒加载的使用场景</h4><ol><li>该页面的 JS 文件体积大，导致页面打开慢，可以通过组件懒加载进行资源拆分，利用浏览器并行下载资源，提升下载速度（比如首页）</li><li>该组件不是一进入页面就展示，需要一定条件下才触发（比如弹框组件）</li><li>该组件复用性高，很多页面都有引入，利用组件懒加载抽离出该组件，一方面可以很好利用缓存，同时也可以减少页面的 JS 文件大小（比如表格组件、图形组件等）</li></ol><h3 id="_3、骨架屏优化白屏时长" tabindex="-1"><a class="header-anchor" href="#_3、骨架屏优化白屏时长" aria-hidden="true">#</a> 3、骨架屏优化白屏时长</h3><p>使用骨架屏，可以缩短白屏时间，提升用户体验。国内大多数的主流网站都使用了骨架屏，特别是手机端的项目</p><p>SPA 单页应用，无论 vue 还是 react，最初的 html 都是空白的，需要通过加载 JS 将内容挂载到根节点上，这套机制的副作用：会造成长时间的白屏</p><p>常见的骨架屏插件就是基于这种原理，在项目打包时将骨架屏的内容直接放到 html 文件的根节点中</p><h3 id="_4、长列表虚拟滚动" tabindex="-1"><a class="header-anchor" href="#_4、长列表虚拟滚动" aria-hidden="true">#</a> 4、长列表虚拟滚动</h3><p>首页中不乏有需要渲染长列表的场景，当渲染条数过多时，所需要的渲染时间会很长，滚动时还会造成页面卡顿，整体体验非常不好</p><p>虚拟滚动——指的是只渲染可视区域的列表项，非可见区域的不渲染，在滚动时动态更新可视区域，该方案在优化大量数据渲染时效果是很明显的</p><p>虚拟滚动基本原理：</p><p>计算出 totalHeight 列表总高度，并在触发时滚动事件时根据 scrollTop 值不断更新 startIndex 以及 endIndex ，以此从列表数据 listData 中截取对应元素</p><h3 id="_5、图片优化" tabindex="-1"><a class="header-anchor" href="#_5、图片优化" aria-hidden="true">#</a> 5、图片优化</h3><p>平常大部分性能优化工作都集中在 JS 方面，但图片也是页面上非常重要的部分</p><p>特别是对于移动端来说，完全没有必要去加载原图，浪费带宽。如何去压缩图片，让图片更快的展示出来，有很多优化工作可以做</p><ol><li>图片的动态裁剪，很多云服务，比如阿里云或七牛云，都提供了图片的动态裁剪功能，只需在图片的url地址上动态添加参数，就可以得到你所需要的尺寸大小</li><li>图片的懒加载，例如 <code>vue-lazyload</code></li><li>使用字体图标</li></ol><p>本文主要介绍的是 <code>代码层面</code> 的性能优化，经过这常规方案的优化，首页打开速度有了不小的提升</p>`,27),t=[p];function i(c,l){return n(),s("div",null,t)}const d=a(o,[["render",i],["__file","xingnenyouhuafangan.html.vue"]]);export{d as default};
